import { CommandLine, CommandRow } from './bundle.min.js';
import { JsonViewer } from '../Json/bundle.js';
import { NexaNpm } from './npm/index.js';
import { developer } from './developer/index.js';
import { bundle } from './developer/bundle/index.js';
import { nxTest } from './developer/test/index.js';
import { mode } from './mode/index.js';
import { debug } from './debug/index.js';
import { problems } from './debug/problems.js';
import { APIConsole } from './api/index.js';
import { agent } from './agent/index.js';


// import { rtdbRotifications } from './notifications.js';
// // import { allVersion, tabelVersion, packaceVersion } from './version.js';
import { TabelRaw, createTableHTML } from './raw/index.js';
import { registerShortcutsCommand } from './shortcuts.js';
import { registerServerCommands } from './server/index.js';

export let NexaCommand;

(() => {
    "use strict";

    NexaCommand = {};

    const CLI_HISTORY_STORE = 'bucketsCli';

    function nexaCliSortHistoryRows(rows) {
        if (!Array.isArray(rows)) {
            return [];
        }
        return [...rows].sort((a, b) => {
            const ta = new Date(a?.updatedAt || a?.createdAt || 0).getTime();
            const tb = new Date(b?.updatedAt || b?.createdAt || 0).getTime();
            return ta - tb;
        });
    }

    async function nexaPersistCliCommand(command) {
        const raw = String(command || '').trim();
        if (!raw) {
            return;
        }
        if (typeof NXUI === 'undefined' || !NXUI.ref || typeof NXUI.ref.set !== 'function') {
            return;
        }
        try {
            // Cek apakah command sama dengan entri terakhir — skip duplikat berurutan
            const existing = await NXUI.ref.getAll(CLI_HISTORY_STORE);
            const rows = existing && Array.isArray(existing.data) ? existing.data : [];
            const sorted = nexaCliSortHistoryRows(rows);
            if (sorted.length > 0) {
                const lastCmd = String(sorted[sorted.length - 1]?.command || '').trim();
                if (lastCmd === raw) return;
            }
            const id = `cli_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
            await NXUI.ref.set(CLI_HISTORY_STORE, { id, command: raw });
        } catch {
            /* ignore */
        }
    }

    NexaCommand.hydrateCliHistory = async function (cmd) {
        if (!cmd) {
            return;
        }
        if (typeof NXUI === 'undefined' || !NXUI.ref || typeof NXUI.ref.getAll !== 'function') {
            return;
        }
        try {
            const res = await NXUI.ref.getAll(CLI_HISTORY_STORE);
            const rows = res && Array.isArray(res.data) ? res.data : [];
            const sorted = nexaCliSortHistoryRows(rows);
            // Deduplikasi: untuk command sama, hanya pertahankan yang paling baru
            const seen = new Set();
            const deduped = [];
            for (let i = sorted.length - 1; i >= 0; i--) {
                const c = String(sorted[i]?.command != null ? sorted[i].command : '').trim();
                if (c && !seen.has(c)) {
                    seen.add(c);
                    deduped.unshift(c);
                }
            }
            cmd.history = deduped;
            cmd.currentHistoryIndex = cmd.history.length;
        } catch {
            /* ignore */
        }
    };

    NexaCommand.instance = (selector, credential = null,db=null) => {
        // Get username from credential if oauth is true, otherwise use default
        const initialUsername = (credential?.oauth && credential?.data?.email) 
            ? credential.data.email 
            : null;
        
        const cmd = new CommandLine(selector, initialUsername);

        // Cegah auto-scroll ke bawah saat user klik di konten terminal.
        // Bundle memanggil commandEntry.focus() di handler click-nya (bubble phase),
        // yang menyebabkan browser scroll ke element yang difokus.
        // Kita simpan scrollTop sebelum click dan restore setelah bundle selesai.
        cmd.container.addEventListener('click', () => {
            const scrollEl = cmd.container;
            const saved = scrollEl.scrollTop;
            setTimeout(() => { scrollEl.scrollTop = saved; }, 0);
        }, true);

        // Store credential and db in closure for access by command handlers
        let userCredential = credential;
        let userDb = db;

        function nexaRemoveTerminalProgressRow(term) {
            const cr = term.commandRow;
            if (cr && cr.commandRow) {
                try {
                    cr.commandRow.remove();
                } catch {
                    /* ignore */
                }
            }
            term.commandRow = null;
        }

        async function nexaRunWithTermWait(commandRef, kind, cwdHint, workFn) {
            const npmUi = new NexaNpm();
            let progressShown = false;
            try {
                await npmUi.ensureStylesheet();
                const progressHtml = npmUi.renderStartStopWait({
                    kind,
                    cwd: cwdHint != null ? String(cwdHint) : '',
                });
                commandRef.output(progressHtml);
                progressShown = true;
                if (commandRef.commandRow) {
                    commandRef.commandRow.hideTime();
                    commandRef.commandRow.commandEntry.classList.add('block');
                }
                const entryEl = commandRef.commandRow && commandRef.commandRow.commandEntry;
                if (entryEl) {
                    npmUi.initStartStopWait(entryEl, {
                        kind,
                        cwd: cwdHint != null ? String(cwdHint) : '',
                    });
                }
                await new Promise((resolve) => {
                    if (typeof requestAnimationFrame === 'function') {
                        requestAnimationFrame(() => requestAnimationFrame(resolve));
                    } else {
                        setTimeout(resolve, 50);
                    }
                });
                return await workFn();
            } finally {
                npmUi.destroy();
                if (progressShown) {
                    nexaRemoveTerminalProgressRow(commandRef);
                }
            }
        }

        const normalizeSlash = (value) => String(value || '').replace(/\/+/g, '/').replace(/\\+/g, '/');

        const resolveInitialCwd = () => {
            try {
                const terminalHost = selector && typeof selector.closest === 'function'
                    ? selector.closest('.beranda-terminal-host')
                    : null;
                const hostCwd = String(terminalHost?.dataset?.terminalCwd || '').trim();
                if (hostCwd) {
                    return shellNormalize(hostCwd);
                }
                const raw = localStorage.getItem('nx-discovery-editor-active');
                if (!raw) return 'D:/';
                const row = JSON.parse(raw);
                const filePath = String(row?.filePath || '').trim();
                if (!filePath) return 'D:/';
                const clean = normalizeSlash(filePath);
                const parts = clean.split('/').filter(Boolean);
                if (!parts.length) return 'D:/';
                parts.pop();
                if (!parts.length) return 'D:/';
                const maybeDrive = parts[0];
                if (/^[a-zA-Z]:$/.test(maybeDrive)) {
                    return `${maybeDrive}/${parts.slice(1).join('/')}`.replace(/\/+$/g, '') || `${maybeDrive}/`;
                }
                return `/${parts.join('/')}`;
            } catch {
                return 'D:/';
            }
        };

        const toDisplayPath = (value) => String(value || '').replace(/\//g, '\\');

        const shellJoin = (base, input) => {
            const cleanBase = normalizeSlash(base || 'D:/');
            const cleanInput = normalizeSlash(input || '');
            if (!cleanInput) return cleanBase;
            if (/^[a-zA-Z]:\//.test(cleanInput) || cleanInput.startsWith('/')) {
                return cleanInput;
            }
            const combined = `${cleanBase.replace(/\/+$/g, '')}/${cleanInput}`;
            return combined;
        };

        const shellNormalize = (inputPath) => {
            const src = normalizeSlash(inputPath || '');
            const hasDrive = /^[a-zA-Z]:\//.test(src);
            const drive = hasDrive ? src.slice(0, 2) : '';
            const rest = hasDrive ? src.slice(2) : src;
            const stack = [];
            for (const seg of rest.split('/')) {
                if (!seg || seg === '.') continue;
                if (seg === '..') {
                    if (stack.length > 0) stack.pop();
                    continue;
                }
                stack.push(seg);
            }
            if (hasDrive) {
                if (stack.length === 0) {
                    return `${drive}/`;
                }
                return `${drive}/${stack.join('/')}`.replace(/\/+$/g, '');
            }
            return `/${stack.join('/')}`.replace(/\/+$/g, '') || '/';
        };

        const shellResolvePath = (pathArg) => {
            const input = String(pathArg || '').trim();
            if (!input) return shellCwd;
            return shellNormalize(shellJoin(shellCwd, input));
        };

        const syncPromptWorkingDirectory = () => {
            try {
                cmd.workingDirectory = toDisplayPath(shellCwd);
                const host = selector && typeof selector.closest === 'function'
                    ? selector.closest('.beranda-terminal-host')
                    : null;
                if (host) {
                    host.dataset.terminalCwd = toDisplayPath(shellCwd);
                }
            } catch {
                /* ignore */
            }
            try {
                localStorage.setItem('nx-terminal-active-cwd', JSON.stringify({ cwd: toDisplayPath(shellCwd), ts: Date.now() }));
            } catch { /* ignore */ }
        };

        const shouldTreatInputAsPathLike = (value) => {
            const s = String(value || '').trim();
            if (!s) {
                return false;
            }
            // Perintah multi-kata seperti `npm start` jangan dipaksa jadi `cd ...`.
            if (/\s+/.test(s)) {
                return false;
            }
            if (/^[A-Za-z]:[\\/]/.test(s) || /^[A-Za-z]:$/.test(s)) {
                return true;
            }
            if (/^\\\\/.test(s)) {
                return true;
            }
            if (s === '.' || s === '..') {
                return true;
            }
            if (/^\.[\\/]/.test(s) || /^\.\.[\\/]/.test(s)) {
                return true;
            }
            if (shellCwd) {
                const firstSeg = s.split(/\s+/)[0];
                const lowFirst = firstSeg.toLowerCase();
                for (let i = 0; i < cmd.commands.length; i++) {
                    if (cmd.commands[i].resolved.getCommand().toLowerCase() === lowFirst) {
                        return false;
                    }
                }
                if (/^[\w.\-\\/\s]+$/.test(s)) {
                    return true;
                }
            }
            return false;
        };

        let shellCwd = shellNormalize(resolveInitialCwd());
        syncPromptWorkingDirectory();

        // ── Autocomplete ──────────────────────────────────────────────────────
        const AC_ID = `nexa-ac-${Date.now()}`;
        let acVisible = false;
        let acItems = [];
        let acIndex = -1;

        function acGetEntry() {
            // bundle set contentEditable via JS property, attribute di DOM bisa lowercase atau mixed
            return cmd.container.querySelector('.command-entry[contenteditable]') || null;
        }

        function acGetInputText() {
            const entry = acGetEntry();
            return entry ? (entry.textContent || '').replace(/ /g, ' ').trimStart() : '';
        }

        function acSetInputText(text) {
            const entry = acGetEntry();
            if (!entry) return;
            entry.textContent = text;
            // pindah kursor ke akhir
            try {
                const range = document.createRange();
                range.selectNodeContents(entry);
                range.collapse(false);
                const sel = window.getSelection();
                sel.removeAllRanges();
                sel.addRange(range);
            } catch { /* ignore */ }
        }

        function acBuildCandidates(prefix) {
            const p = prefix.toLowerCase();
            const commandNames = cmd.commands
                ? cmd.commands.map((c) => String(c.resolved?.getCommand?.() || c.resolved?.getSignature?.() || '').split(/\s+/)[0]).filter(Boolean)
                : [];
            const historyItems = Array.isArray(cmd.history) ? [...cmd.history].reverse() : [];
            const seen = new Set();
            const results = [];

            // History dulu (lebih relevan)
            for (const h of historyItems) {
                const word = String(h || '').trim();
                if (word && word.toLowerCase().startsWith(p) && !seen.has(word)) {
                    seen.add(word);
                    results.push({ text: word, type: 'history' });
                }
            }
            // Built-in commands
            for (const name of commandNames) {
                if (name && name.toLowerCase().startsWith(p) && !seen.has(name)) {
                    seen.add(name);
                    results.push({ text: name, type: 'command' });
                }
            }
            return results;
        }

        function acEnsureStyles() {
            if (document.getElementById('nexa-ac-styles')) return;
            const style = document.createElement('style');
            style.id = 'nexa-ac-styles';
            style.textContent = `
.nexa-ac-popup {
  position: fixed;
  z-index: 99999;
  min-width: 200px;
  max-width: 380px;
  max-height: 210px;
  overflow-y: auto;
  padding: 3px 0;
  border-radius: 6px;
  font-family: var(--beranda-font-mono, 'Cascadia Code', 'Consolas', monospace);
  font-size: 12px;
  /* dark default (terminal selalu gelap) */
  background: var(--dm-bg-card, #2c3039);
  border: 1px solid var(--dm-border, #404652);
  box-shadow: 0 6px 20px rgba(0,0,0,.45), 0 1px 4px rgba(0,0,0,.3);
  scrollbar-width: thin;
  scrollbar-color: var(--dm-border, #404652) transparent;
}
.nexa-ac-popup::-webkit-scrollbar { width: 4px; }
.nexa-ac-popup::-webkit-scrollbar-track { background: transparent; }
.nexa-ac-popup::-webkit-scrollbar-thumb { background: var(--dm-border, #404652); border-radius: 4px; }

/* light mode override */
body:not(.dark-mode-grid) .nexa-ac-popup {
  background: var(--beranda-dv-surface, #ffffff);
  border-color: var(--beranda-dv-header-border, #d0d7de);
  box-shadow: 0 4px 14px rgba(0,0,0,.12), 0 1px 3px rgba(0,0,0,.08);
}

.nexa-ac-item {
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 5px 10px;
  cursor: pointer;
  color: var(--dm-text-main, #d4d7dc);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  line-height: 1.4;
  border-radius: 3px;
  margin: 1px 3px;
  transition: background 80ms;
}
body:not(.dark-mode-grid) .nexa-ac-item {
  color: var(--beranda-fg, #1f2328);
}
.nexa-ac-item:hover,
.nexa-ac-item.ac-active {
  background: var(--dm-bg-hover, rgba(255,255,255,.08));
  color: var(--dm-text-main, #ffffff);
}
body:not(.dark-mode-grid) .nexa-ac-item:hover,
body:not(.dark-mode-grid) .nexa-ac-item.ac-active {
  background: var(--beranda-dv-hover, #eaeef2);
  color: var(--beranda-fg, #1f2328);
}

.nexa-ac-icon {
  font-size: 13px;
  flex-shrink: 0;
  opacity: .7;
  font-family: 'Material Symbols Outlined', sans-serif;
  font-variation-settings: 'FILL' 0, 'wght' 300, 'GRAD' 0, 'opsz' 16;
  line-height: 1;
  user-select: none;
}
.nexa-ac-icon-h { color: var(--dm-green-accent, #7ec87e); }
.nexa-ac-icon-c { color: var(--dm-blue-accent, #6cb2ff); }
body:not(.dark-mode-grid) .nexa-ac-icon-h { color: #2da44e; }
body:not(.dark-mode-grid) .nexa-ac-icon-c { color: #0969da; }

.nexa-ac-text { flex: 1; overflow: hidden; text-overflow: ellipsis; }
.nexa-ac-text mark {
  background: none;
  color: var(--dm-blue-accent, #6cb2ff);
  font-weight: 600;
}
body:not(.dark-mode-grid) .nexa-ac-text mark { color: var(--beranda-dv-accent, #0969da); }

.nexa-ac-hint {
  font-size: 10px;
  color: var(--dm-text-secondary, #969696);
  flex-shrink: 0;
  margin-left: auto;
  padding-left: 6px;
}
body:not(.dark-mode-grid) .nexa-ac-hint { color: var(--beranda-fg-muted, #57606a); }
`;
            document.head.appendChild(style);
        }

        function acHide() {
            const el = document.getElementById(AC_ID);
            if (el) el.remove();
            acVisible = false;
            acItems = [];
            acIndex = -1;
        }

        function acHighlightPrefix(text, prefix) {
            if (!prefix) return escHtml(text);
            const len = prefix.length;
            if (text.toLowerCase().startsWith(prefix.toLowerCase())) {
                return `<mark>${escHtml(text.slice(0, len))}</mark>${escHtml(text.slice(len))}`;
            }
            return escHtml(text);
        }

        function escHtml(s) {
            return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        }

        function acShow(items, anchorEl) {
            acHide();
            if (!items.length) return;
            acEnsureStyles();
            acItems = items;
            acIndex = -1;
            acVisible = true;

            const prefix = acGetInputText();
            const menu = document.createElement('div');
            menu.id = AC_ID;
            menu.className = 'nexa-ac-popup';
            menu.setAttribute('role', 'listbox');

            items.forEach((item, i) => {
                const div = document.createElement('div');
                div.className = 'nexa-ac-item';
                div.setAttribute('role', 'option');
                div.dataset.idx = String(i);

                const icon = document.createElement('span');
                icon.className = `nexa-ac-icon ${item.type === 'history' ? 'nexa-ac-icon-h' : 'nexa-ac-icon-c'}`;
                icon.textContent = item.type === 'history' ? 'history' : 'terminal';
                icon.setAttribute('aria-hidden', 'true');

                const label = document.createElement('span');
                label.className = 'nexa-ac-text';
                label.innerHTML = acHighlightPrefix(item.text, prefix);

                div.appendChild(icon);
                div.appendChild(label);

                if (item.type === 'history') {
                    const hint = document.createElement('span');
                    hint.className = 'nexa-ac-hint';
                    hint.textContent = 'hist';
                    div.appendChild(hint);
                }

                div.addEventListener('mousedown', (e) => {
                    e.preventDefault();
                    acSetInputText(item.text);
                    acHide();
                    acGetEntry()?.focus();
                });
                menu.appendChild(div);
            });

            document.body.appendChild(menu);

            // Posisi cerdas: tampilkan di atas entry jika terlalu dekat bawah layar
            const rect = anchorEl ? anchorEl.getBoundingClientRect() : { left: 60, top: 200, bottom: 220 };
            const menuH = Math.min(items.length * 30 + 6, 210);
            const spaceBelow = window.innerHeight - rect.bottom;
            const spaceAbove = rect.top;
            let top;
            if (spaceBelow >= menuH || spaceBelow >= spaceAbove) {
                top = rect.bottom + 4;
            } else {
                top = rect.top - menuH - 4;
            }
            menu.style.left = `${Math.max(4, rect.left)}px`;
            menu.style.top = `${Math.max(4, top)}px`;

            acSetActive(0);
        }

        function acSetActive(idx) {
            const menu = document.getElementById(AC_ID);
            if (!menu) return;
            const items = menu.querySelectorAll('.nexa-ac-item');
            items.forEach((el) => el.classList.remove('ac-active'));
            if (idx >= 0 && idx < items.length) {
                items[idx].classList.add('ac-active');
                items[idx].scrollIntoView({ block: 'nearest' });
            }
            acIndex = idx;
        }

        function acTrigger() {
            const text = acGetInputText();
            if (!text) { acHide(); return; }
            const candidates = acBuildCandidates(text);
            if (candidates.length === 1 && candidates[0].text === text) { acHide(); return; }
            acShow(candidates, acGetEntry());
        }

        function acAccept() {
            if (!acVisible || acItems.length === 0) return false;
            const idx = acIndex >= 0 ? acIndex : 0;
            if (acItems[idx]) {
                acSetInputText(acItems[idx].text);
                acHide();
                acGetEntry()?.focus();
            }
            return true;
        }

        // Tutup saat klik di luar
        document.addEventListener('mousedown', (e) => {
            const menu = document.getElementById(AC_ID);
            if (menu && !menu.contains(e.target)) acHide();
        }, true);

        // Attach ke commandEntry langsung (capture = true agar jalan sebelum bundle's listener)
        function acAttachToEntry(entry) {
            if (!entry || entry.__acAttached) return;
            entry.__acAttached = true;

            entry.addEventListener('keydown', (e) => {
                // Jangan intercept saat commandRow dalam mode isolated (prompt/secret/confirm)
                if (cmd.commandRow?.isIsolated?.()) {
                    acHide();
                    return;
                }
                // Tab: intercept sebelum bundle
                if (e.key === 'Tab' || e.keyCode === 9) {
                    e.preventDefault();
                    e.stopImmediatePropagation();
                    if (acVisible) {
                        acAccept();
                    } else {
                        acTrigger();
                    }
                    return;
                }
                if (acVisible) {
                    if (e.key === 'ArrowDown' || e.keyCode === 40) {
                        e.preventDefault();
                        e.stopImmediatePropagation();
                        acSetActive(Math.min(acIndex + 1, acItems.length - 1));
                        return;
                    }
                    if (e.key === 'ArrowUp' || e.keyCode === 38) {
                        e.preventDefault();
                        e.stopImmediatePropagation();
                        acSetActive(Math.max(acIndex - 1, 0));
                        return;
                    }
                    if (e.key === 'Enter' || e.keyCode === 13) {
                        if (acAccept()) {
                            e.preventDefault();
                            e.stopImmediatePropagation();
                        }
                        return;
                    }
                    if (e.key === 'Escape') {
                        acHide();
                        return;
                    }
                }
            }, true); // capture = true: jalan sebelum listener bundle

            entry.addEventListener('input', () => {
                // Jangan trigger saat mode isolated (prompt/secret/confirm)
                if (cmd.commandRow?.isIsolated?.()) {
                    acHide();
                    return;
                }
                const text = acGetInputText();
                if (!text) { acHide(); return; }
                const candidates = acBuildCandidates(text);
                if (candidates.length === 0 || (candidates.length === 1 && candidates[0].text === text)) {
                    acHide(); return;
                }
                acShow(candidates, entry);
            });
        }

        // Patch startNewCommand agar setiap baris baru otomatis ter-attach
        const origStartNewCommand = cmd.startNewCommand.bind(cmd);
        cmd.startNewCommand = function (...args) {
            acHide();
            const savedScroll = cmd.container.scrollTop;
            origStartNewCommand(...args);
            // commandEntry baru baru saja dibuat — attach di tick berikutnya
            requestAnimationFrame(() => {
                const entry = cmd.container.querySelector('.command-entry[contenteditable]');
                if (entry) acAttachToEntry(entry);
                // Cegah scroll otomatis akibat focus() yang dipanggil bundle
                cmd.container.scrollTop = savedScroll;
            });
        };

        // Attach ke entry pertama (saat ini sudah ada sebelum patch aktif)
        requestAnimationFrame(() => {
            const entry = cmd.container.querySelector('.command-entry[contenteditable]');
            if (entry) acAttachToEntry(entry);
        });

        // ── End Autocomplete ──────────────────────────────────────────────────

        const origRun = cmd.run.bind(cmd);
        cmd.run = function (command) {
            acHide();
            const raw = String(command || '').trim();
            const effectiveCommand = shouldTreatInputAsPathLike(raw) ? `cd ${raw}` : raw;
            void nexaPersistCliCommand(effectiveCommand);
            // Cek apakah command terdaftar
            const firstWord = raw.split(/\s+/)[0] || '';
            const isRegistered = firstWord && cmd.commands.some(
                (c) => c.resolved.getCommand().toLowerCase() === firstWord.toLowerCase()
            );
            if (isRegistered) {
                origRun(effectiveCommand);
                return;
            }
            // Tidak terdaftar — coba native shell
            if (firstWord && !/^(cd|home|help|clear|cls|pwd|login|logout|date|whoami|shortcuts|output-mode|output-clean|output-raw|clean|raw|shell-stop|stop-shell)$/i.test(firstWord)) {
                // dispatch ke native shell — stop() otomatis setelah command selesai
                const runPromise = runNativeShellCommand(raw);
                if (runPromise && typeof runPromise.then === 'function') {
                    runPromise.then(() => { try { cmd.stop(); } catch { /* ignore */ } });
                }
                return;
            }
            // Fallback: biarkan origRun yang menangani error
            origRun(effectiveCommand);
        };

        /**
         * Set command line username  by command argument
         */
        cmd.addCommand("update-user username", (command) => {
            cmd.setUsername(command.getArgument('username'));
        }, "Set username  by command argument");
 
        /**
         * Set command line username from prompt
         */
        // cmd.addCommand("nxdev",async  function promptHandler() {
        //     return  await developer(cmd);
        // }, 'Developer Extensions');


    


      
        
        /**
         * Set command line username from prompt
         */
        cmd.addCommand("prompt", function promptHandler() {
            const retryPrompt = (userInput) => {
                if (userInput === '') {
                    cmd.error("Your name cannot be empty!");
                    cmd.prompt("type your name", retryPrompt);
                } else {
                    cmd.setUsername(userInput);
                    cmd.startNewCommand();
                }
            };
            cmd.prompt("type your name", retryPrompt);
            return false;
        }, 'Set username from prompt ');

        /**
         * Confirmation to remove all file ;)
         */
        cmd.addCommand("rm args*", async function (command) {
            const args = String(command.getArgument('args') || '').trim();
            const full = `rm${args ? ` ${args}` : ''}`;
            await runNativeShellCommand(full);
        }, 'Remove files/directories via native shell');
       
      
        /**
         * Help :)
         */
        cmd.addCommand("help", function () {
            const helpResults = [];
            for (let command = 0; command < cmd.commands.length; command++) {
                const commandName = cmd.commands[command].resolved.getSignature();
                helpResults.push(commandName);
                helpResults.push(cmd.commands[command].description);
            }
            cmd.list(helpResults, 2);
        }, "Show available commands");

        /**
         * Clear terminal screen
         */
        cmd.addCommand("clear", function () {
            cmd.container.innerHTML = '';
            cmd.startNewCommand();
            return false;
        }, 'Clear terminal screen');

        cmd.addCommand("cls", function () {
            cmd.container.innerHTML = '';
            cmd.startNewCommand();
            return false;
        }, 'Clear terminal screen (alias)');

        cmd.addCommand("pwd", function () {
            cmd.output(toDisplayPath(shellCwd));
            try { cmd.commandRow?.hideTime?.(); } catch { /* ignore */ }
        }, 'Show current working directory');

        cmd.addCommand("cd path?", async function (command) {
            const pathArg = String(command.getArgument('path') || '').trim();
            if (!pathArg) {
                cmd.output(toDisplayPath(shellCwd));
                return;
            }

            const target = shellResolvePath(pathArg);
            if (window.electronAPI?.discoveryReadFolder) {
                try {
                    const row = await window.electronAPI.discoveryReadFolder(target.replace(/\//g, '\\'));
                    if (!row?.ok) {
                        cmd.error(`Path not found: ${toDisplayPath(target)}`);
                        return;
                    }
                    shellCwd = shellNormalize(normalizeSlash(row.path || target));
                    syncPromptWorkingDirectory();
                    cmd.success(toDisplayPath(shellCwd));
                    return;
                } catch {
                    cmd.error(`Path not found: ${toDisplayPath(target)}`);
                    return;
                }
            }

            shellCwd = target;
            syncPromptWorkingDirectory();
            cmd.success(toDisplayPath(shellCwd));
        }, 'Change current directory');

        cmd.addCommand('home', function () {
            shellCwd = shellNormalize('D:/');
            syncPromptWorkingDirectory();
            cmd.success('cwd reset to home');
        }, 'Reset cwd to default');

        function renderLsTable(entries) {
            const isDark = !cmd.container?.classList?.contains('light');
            const clr = isDark
                ? { head: '#636d83', dir: '#56b6c2', file: '#f8f8f2', date: '#a8cc8c', size: '#d19a66', line: '#2d3139' }
                : { head: '#64748b', dir: '#0070a8', file: '#1a1a2e', date: '#1a7a3a', size: '#b85c00', line: '#e2e8f0' };

            const fmtDate = (iso) => {
                if (!iso) return '               ';
                try {
                    const d = new Date(iso);
                    const mo = String(d.getMonth() + 1).padStart(2, '0');
                    const da = String(d.getDate()).padStart(2, '0');
                    const yr = d.getFullYear();
                    let h = d.getHours(), suf = 'AM';
                    if (h >= 12) { suf = 'PM'; if (h > 12) h -= 12; }
                    if (h === 0) h = 12;
                    const mi = String(d.getMinutes()).padStart(2, '0');
                    return `${mo}/${da}/${yr} ${String(h).padStart(2, ' ')}:${mi} ${suf}`;
                } catch { return '               '; }
            };

            const fmtSize = (size, type) => {
                if (type === 'directory') return '';
                if (size == null) return '';
                if (size < 1024) return String(size);
                if (size < 1024 * 1024) return (size / 1024).toFixed(1) + ' KB';
                return (size / (1024 * 1024)).toFixed(1) + ' MB';
            };

            const fmtMode = (type) => type === 'directory' ? 'd----' : '-a---';

            // Hitung lebar kolom size
            const sizes = entries.map((e) => fmtSize(e.size, e.type));
            const maxSize = Math.max(6, ...sizes.map((s) => s.length));

            const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
            const sp = (s, n, right = false) => {
                const str = String(s);
                const pad = Math.max(0, n - str.length);
                return right ? ' '.repeat(pad) + str : str + ' '.repeat(pad);
            };

            const hLine = (color, text, w, right) =>
                `<span style="color:${color}">${esc(sp(text, w, right))}</span>`;

            // Header
            let html = '<pre style="margin:4px 0;font-family:Cascadia Mono,Consolas,monospace;font-size:11px;line-height:1.6;white-space:pre;">';
            html += hLine(clr.head, 'Mode', 6) + '  ';
            html += hLine(clr.head, 'LastWriteTime', 20) + '  ';
            html += hLine(clr.head, 'Length', maxSize, true) + '  ';
            html += hLine(clr.head, 'Name', 4) + '\n';
            html += hLine(clr.head, '----', 6) + '  ';
            html += hLine(clr.head, '-------------', 20) + '  ';
            html += hLine(clr.head, '------', maxSize, true) + '  ';
            html += hLine(clr.head, '----', 4) + '\n';

            for (const e of entries) {
                const isDir = e.type === 'directory';
                const nameClr = isDir ? clr.dir : clr.file;
                const sz = fmtSize(e.size, e.type);
                html += `<span style="color:${clr.head}">${esc(fmtMode(e.type))} </span> `;
                html += `<span style="color:${clr.date}">${esc(sp(fmtDate(e.mtime), 20))}</span>  `;
                html += `<span style="color:${clr.size}">${esc(sp(sz, maxSize, true))}</span>  `;
                html += `<span style="color:${nameClr}">${esc(e.name)}</span>\n`;
            }
            html += '</pre>';
            return html;
        }

        cmd.addCommand("ls args*", async function (command) {
            const args = String(command.getArgument('args') || '').trim();
            // Jika ada flag (dimulai -) → forward ke native shell
            if (args && /^-/.test(args.split(/\s+/)[0])) {
                await runNativeShellCommand(`ls ${args}`);
                return;
            }
            const pathArg = args;
            const target = shellResolvePath(pathArg);
            if (window.electronAPI?.terminalLs) {
                try {
                    const row = await window.electronAPI.terminalLs(target.replace(/\//g, '\\'));
                    if (!row?.ok) { cmd.error(`Cannot read path: ${toDisplayPath(target)}`); return; }
                    const entries = Array.isArray(row.entries) ? row.entries : [];
                    if (!entries.length) { cmd.info('(empty)'); return; }
                    cmd.output(renderLsTable(entries));
                    return;
                } catch {
                    cmd.error(`Cannot read path: ${toDisplayPath(target)}`);
                    return;
                }
            }
            cmd.list(['Applications','Library','Users','etc','home','var','System'], 1);
        }, 'List directory files');

        cmd.addCommand("dir args*", async function (command) {
            const args = String(command.getArgument('args') || '').trim();
            // Jika ada flag (dimulai /) → forward ke native shell (cmd.exe dir /w dll)
            if (args && /^[\/\-]/.test(args.split(/\s+/)[0])) {
                await runNativeShellCommand(`dir ${args}`);
                return;
            }
            const pathArg = args;
            const target = shellResolvePath(pathArg);
            if (window.electronAPI?.terminalLs) {
                try {
                    const row = await window.electronAPI.terminalLs(target.replace(/\//g, '\\'));
                    if (!row?.ok) { cmd.error(`Cannot read path: ${toDisplayPath(target)}`); return; }
                    const entries = Array.isArray(row.entries) ? row.entries : [];
                    if (!entries.length) { cmd.info('(empty)'); return; }
                    cmd.output(renderLsTable(entries));
                    return;
                } catch {
                    cmd.error(`Cannot read path: ${toDisplayPath(target)}`);
                    return;
                }
            }
            cmd.list(['Applications','Library','Users','etc','home','var','System'], 1);
        }, 'List directory (alias ls)');

        const interactiveSession = { requestId: '', isExpo: false, webUrl: '', openingWeb: false, nodeServerPort: 0, nodeServerUrl: '', nodeServerOpened: false };
        const OUTPUT_MODE_STORAGE_KEY = 'nx-terminal-output-mode';
        const readTerminalOutputMode = () => {
            try {
                const raw = String(localStorage.getItem(OUTPUT_MODE_STORAGE_KEY) || '').trim().toLowerCase();
                return raw === 'raw' ? 'raw' : 'clean';
            } catch {
                return 'clean';
            }
        };
        const writeTerminalOutputMode = (mode) => {
            const normalized = String(mode || '').trim().toLowerCase() === 'raw' ? 'raw' : 'clean';
            try {
                localStorage.setItem(OUTPUT_MODE_STORAGE_KEY, normalized);
            } catch {
                /* ignore */
            }
            return normalized;
        };
        let terminalOutputMode = readTerminalOutputMode();
        let activeShellRequestId = '';
        const resolveTerminalHost = () => {
            try {
                return selector && typeof selector.closest === 'function'
                    ? selector.closest('.beranda-terminal-host')
                    : null;
            } catch {
                return null;
            }
        };
        const dispatchTerminalState = (state, extra = {}) => {
            const host = resolveTerminalHost();
            const hostId = String(host?.dataset?.terminalHostId || '').trim();
            const cwd = toDisplayPath(shellCwd);
            if (host) {
                host.dataset.terminalProcessState = String(state || 'idle');
                host.dataset.terminalCwd = cwd;
                if (activeShellRequestId) {
                    host.dataset.terminalRequestId = activeShellRequestId;
                } else {
                    delete host.dataset.terminalRequestId;
                }
            }
            if (typeof window !== 'undefined') {
                window.dispatchEvent(
                    new CustomEvent('nexa-terminal-state', {
                        detail: {
                            hostId,
                            state,
                            cwd,
                            requestId: activeShellRequestId,
                            ...extra,
                        },
                    }),
                );
            }
        };
        const isInteractiveShellCommand = (text) => /^(npm|pnpm|yarn)\s+(start|run\s+dev)\b/i.test(String(text || '').trim())
            || /^(npx\s+expo|expo)\s+start\b/i.test(String(text || '').trim());
        const mapKeyToPty = (e) => {
            if (e.ctrlKey && (e.key === 'c' || e.key === 'C')) return '\x03';
            if (e.key === 'Enter') return '\r';
            if (e.key === 'Tab') return '\t';
            if (e.key === 'Backspace') return '\x7f';
            if (e.key === 'ArrowUp') return '\x1b[A';
            if (e.key === 'ArrowDown') return '\x1b[B';
            if (e.key === 'ArrowRight') return '\x1b[C';
            if (e.key === 'ArrowLeft') return '\x1b[D';
            if (e.key === 'Escape') return '\x1b';
            if (e.key.length === 1 && !e.metaKey && !e.altKey) return e.key;
            return '';
        };
        const decodeTerminalDisplayUrls = (text) => {
            try {
                if (cmd?._decodeDisplayUrls) return cmd._decodeDisplayUrls(text);
            } catch { /* ignore */ }
            let s = String(text || '');
            s = s.replace(/\b(url=)([^&\s'"<>]+)/gi, (_, key, value) => {
                if (!/%[0-9A-Fa-f]{2}/.test(value)) return key + value;
                try {
                    return key + decodeURIComponent(value.replace(/\+/g, '%2B'));
                } catch {
                    return key + value;
                }
            });
            s = s.replace(/https?%3A%2F%2F[^\s)]+/gi, (token) => {
                try { return decodeURIComponent(token); } catch { return token; }
            });
            return s;
        };
        const parseExpoWebUrl = (text) => {
            const decoded = decodeTerminalDisplayUrls(text);
            const m = decoded.match(/Web is waiting on\s+(https?:\/\/[^\s]+)/i);
            if (m?.[1]) return String(m[1]).trim();
            const q = decoded.match(/\burl=(https?:\/\/[^&\s]+)/i);
            if (q?.[1]) return String(q[1]).trim();
            const enc = String(text || '').match(/\burl=(https?%3A%2F%2F[^&\s]+)/i);
            if (enc?.[1]) {
                try { return decodeURIComponent(enc[1].replace(/\+/g, '%2B')); } catch { /* ignore */ }
            }
            return '';
        };
        const openExpoWebInBerandaWebview = async () => {
            if (interactiveSession.openingWeb) {
                cmd.info('Expo webview masih diproses, mohon tunggu...');
                return true;
            }
            const url = String(interactiveSession.webUrl || '').trim();
            if (!url) {
                cmd.warning('URL Expo web belum siap. Tunggu "Web is waiting on ..." lalu tekan v lagi.');
                return false;
            }
            interactiveSession.openingWeb = true;
            cmd.info(`Membuka Expo webview panel... ${url}`);
            try {
                const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
                const isReady = async () => {
                    if (!window.electronAPI?.warmExpoWeb) return false;
                    try {
                        const res = await window.electronAPI.warmExpoWeb({ url });
                        return Boolean(res?.ok);
                    } catch {
                        return false;
                    }
                };
                let ready = await isReady();
                for (let i = 0; !ready && i < 16; i += 1) {
                    await wait(250);
                    ready = await isReady();
                }
                let opened = null;
                if (typeof globalThis.openBerandaWebviewPanel === 'function') {
                    opened = await globalThis.openBerandaWebviewPanel(url);
                } else if (typeof window !== 'undefined') {
                    window.dispatchEvent(new CustomEvent('nexa-open-webview-panel', { detail: { url } }));
                    opened = { ok: true };
                }
                if (opened?.ok === false) {
                    cmd.error(String(opened?.error || 'Gagal membuka panel Webview.'));
                    return false;
                }
                cmd.info(`Expo web ditampilkan di panel Webview: ${url}`);
                return true;
            } catch {
                cmd.error('Gagal membuka panel Webview.');
                return false;
            } finally {
                interactiveSession.openingWeb = false;
            }
        };
        const openExpoWebInElectron = async () => {
            if (interactiveSession.openingWeb) {
                cmd.info('Expo web masih diproses, mohon tunggu...');
                return true;
            }
            const url = String(interactiveSession.webUrl || '').trim();
            if (!url || !window.electronAPI?.openWebWindow) {
                cmd.warning('URL Expo web belum siap. Tunggu "Web is waiting on ..." lalu tekan w lagi.');
                return false;
            }
            interactiveSession.openingWeb = true;
            cmd.info(`Membuka Expo web... ${url}`);
            try {
                const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
                const isReady = async () => {
                    if (!window.electronAPI?.warmExpoWeb) return false;
                    try {
                        const res = await window.electronAPI.warmExpoWeb({ url });
                        return Boolean(res?.ok);
                    } catch {
                        return false;
                    }
                };
                let ready = await isReady();
                for (let i = 0; !ready && i < 16; i += 1) {
                    await wait(250);
                    ready = await isReady();
                }
                await window.electronAPI.openWebWindow({
                    url,
                    width: 390,
                    height: 844,
                    minWidth: 360,
                    minHeight: 640,
                    title: `Expo Web - ${url}`,
                    reload: true,
                });
                cmd.info(`Expo web opened in Electron: ${url}`);
                return true;
            } catch {
                cmd.error('Gagal membuka Expo web window.');
                return false;
            } finally {
                interactiveSession.openingWeb = false;
            }
        };
        cmd.container.setAttribute('tabindex', '0');
        cmd.container.addEventListener('keydown', async (e) => {
            const reqId = String(interactiveSession.requestId || activeShellRequestId || '');
            const isCtrlC = e.ctrlKey && (e.key === 'c' || e.key === 'C');

            // Ctrl+C selalu dihandle di semua kondisi
            if (isCtrlC) {
                e.preventDefault();
                e.stopPropagation();
                if (reqId && window.electronAPI?.terminalShellWrite) {
                    // Ada proses PTY aktif — kirim SIGINT ke shell
                    void window.electronAPI.terminalShellWrite({ requestId: reqId, data: '\x03' });
                } else {
                    // Tidak ada proses — cancel/clear baris input terminal
                    try { cmd.cancel?.(); } catch { /* ignore */ }
                    try { cmd.startNewCommand?.(); } catch { /* ignore */ }
                }
                return;
            }

            if (!reqId) return;

            if (interactiveSession.isExpo && !e.ctrlKey && !e.metaKey && !e.altKey) {
                const key = String(e.key || '').toLowerCase();
                if (key === 'w') {
                    const opened = await openExpoWebInElectron();
                    if (opened) {
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
                if (key === 'v') {
                    const opened = await openExpoWebInBerandaWebview();
                    if (opened) {
                        e.preventDefault();
                        e.stopPropagation();
                        return;
                    }
                }
            }
            const data = mapKeyToPty(e);
            if (!data || !window.electronAPI?.terminalShellWrite) return;
            e.preventDefault();
            e.stopPropagation();
            void window.electronAPI.terminalShellWrite({ requestId: reqId, data });
        }, true);

        const getActiveShell = () => {
            try { return localStorage.getItem('beranda-terminal-active-shell') || 'default'; } catch { return 'default'; }
        };

        // Alias PS bawaan yang tidak ada di cmd.exe
        const _psAliases = new Set([
            'gci','gal','gcm','gcs','gdr','ghy','gin','gjb','gl','gm','gmo','go','gp','gps',
            'gpv','gsnp','gsv','gu','gv','gwmi','iex','ii','ipal','ipmo','ipsn','irm','ise',
            'iwmi','iwr','kill','lp','ls','man','md','mi','mp','mv','nal','ndr','ni','nmo',
            'npssc','nsn','nv','oh','rbp','rcjb','rdr','rm','rmo','rni','rnp','rp','rsn',
            'rsnp','rujb','rv','rvpa','rwmi','sajb','sal','saps','sasv','sbp','scb','select',
            'set','shcm','si','sl','sleep','smo','spsv','start','sujb','sv','swmi','tee',
            'trcm','type','where','wjb','write','ac','asnp','clc','cli','clp','clv','cnsn',
            'compare','copy','cpp','cvpa','dbp','del','diff','dir','dnsn','ebp','echo',
            'epal','epcsv','epsn','erase','etsn','exsn','fc','fl','foreach','ft','fw',
            'gbp','gc','gcb',
        ]);

        // PS cmdlets & operators yang tidak dikenal cmd.exe — perlu wrapped ke powershell -Command
        const isPsNativeSyntax = (text) => {
            const t = String(text || '');
            const firstWord = t.trim().split(/\s+/)[0] || '';
            // Cmdlet pattern: Verb-Noun (Get-Item, Set-Location, Write-Host, dll.)
            if (/\b[A-Z][a-z]+-[A-Z][A-Za-z]+\b/.test(t)) return true;
            // PS alias yang tidak ada di cmd.exe
            if (_psAliases.has(firstWord.toLowerCase())) return true;
            // PS-only operators & syntax
            if (/\$\w+|\$\{|\$env:|\bforeach\s*\(|\bparam\s*\(/.test(t)) return true;
            // PS pipeline dengan cmdlets
            if (/\|\s*[A-Z][a-z]+-[A-Z][A-Za-z]+\b/.test(t)) return true;
            // PS redirection & common cmdlets
            if (/>\$null\b|\bOut-Null\b|\bSelect-Object\b|\bWhere-Object\b|\bForEach-Object\b/.test(t)) return true;
            // PS operators: -eq, -ne, -gt, -lt, -like, -match (tidak ada di cmd.exe)
            if (/\s-(?:eq|ne|gt|lt|ge|le|like|notlike|match|notmatch|contains|in|is|isnot)\b/i.test(t)) return true;
            return false;
        };

        const wrapForActiveShell = (command) => {
            const shell = getActiveShell();
            if (shell !== 'powershell' && shell !== 'pwsh') return command;
            // Sudah di-wrap sebelumnya — jangan double wrap
            if (/^(powershell|pwsh)(\s+|\.exe)/i.test(command)) return command;
            // Perintah yg cmd.exe juga mengerti dan tidak ada PS syntax khusus — biarkan
            if (!isPsNativeSyntax(command)) return command;
            const bin = shell === 'pwsh' ? 'pwsh' : 'powershell';
            // Escape kutip ganda agar tidak merusak string -Command "..."
            const escaped = command.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
            return `${bin} -NoProfile -NonInteractive -Command "${escaped}"`;
        };

        const runNativeShellCommand = async (fullCommand) => {
            const raw = String(fullCommand || '').trim();
            if (!raw) return;
            let execCommand = raw;
            if (!window.electronAPI?.terminalShellStream || !window.electronAPI?.onTerminalShellData || !window.electronAPI?.onTerminalShellExit) {
                cmd.error('API terminalShellStream belum tersedia. Restart aplikasi Electron.');
                return;
            }
            if (/^npm\s+start$/i.test(raw) && window.electronAPI?.discoveryReadFile && window.electronAPI?.terminalCheckPort && window.electronAPI?.terminalFreePort) {
                try {
                    const packagePath = `${shellCwd.replace(/\//g, '\\')}\\package.json`;
                    const pkgRes = await window.electronAPI.discoveryReadFile(packagePath);
                    if (pkgRes?.ok && pkgRes?.content) {
                        const pkg = JSON.parse(String(pkgRes.content || '{}'));
                        const startScript = String(pkg?.scripts?.start || '').trim();
                        // Guard khusus Electron app: pakai user-data-dir lokal agar cache tidak bentrok permission di %APPDATA%.
                        if (/\belectron(?:mon)?\b/i.test(startScript) && !/--user-data-dir\b/i.test(raw)) {
                            const userDataDir = `${shellCwd.replace(/\//g, '\\')}\\.electron-userdata-dev`;
                            execCommand = `${raw} -- --user-data-dir="${userDataDir}" --disable-gpu-shader-disk-cache`;
                        }
                        const m = startScript.match(/\bexpo\s+start\b[\s\S]*?--port\s+(\d+)/i);
                        const port = Number(m?.[1] || 0);
                        if (Number.isFinite(port) && port > 0) {
                            const state = await window.electronAPI.terminalCheckPort({ port });
                            if (state?.ok && state?.free === false) {
                                const freed = await window.electronAPI.terminalFreePort({ port });
                                if (freed?.ok && Array.isArray(freed.killed) && freed.killed.length > 0) {
                                    cmd.warning(`Port ${port} sedang dipakai, proses lama dihentikan: ${freed.killed.join(', ')}`);
                                }
                                const verify = await window.electronAPI.terminalCheckPort({ port });
                                if (!verify?.ok || verify?.free === false) {
                                    cmd.error(`Port ${port} masih dipakai proses lain. Stop dulu proses di luar aplikasi, lalu jalankan lagi npm start.`);
                                    return;
                                }
                            }
                        }
                    }
                } catch {
                    /* ignore */
                }
            }
            execCommand = wrapForActiveShell(execCommand);
            const cwdWin = shellCwd.replace(/\//g, '\\');
            const requestId = `term_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
            activeShellRequestId = requestId;
            const isElectronNpmStart = /^npm\s+start\b/i.test(execCommand)
                && /--user-data-dir\s*=|--user-data-dir\s+"|--disable-gpu-shader-disk-cache/i.test(execCommand);
            const interactive = isInteractiveShellCommand(execCommand) && !isElectronNpmStart;
            if (interactive) {
                interactiveSession.requestId = requestId;
                interactiveSession.isExpo = /\b(?:npx\s+expo|expo)\s+start\b/i.test(execCommand)
                    || /^npm\s+start$/i.test(execCommand)
                    || /^npm\s+run\s+dev$/i.test(execCommand);
                interactiveSession.webUrl = '';
                try { cmd.container.focus(); } catch { /* ignore */ }
            }
            dispatchTerminalState('running', { command: execCommand, interactive: Boolean(interactive) });
            const stdoutState = { buffer: '' };
            const stderrState = { buffer: '' };
            const streamOut = { liveRow: null, progressRow: null, lastLine: '' };

            const isBundlerProgressLine = (text) => {
                const t = String(text || '').trim();
                if (!t) return false;
                if (/^Web Bundled\s+\d+ms/i.test(t)) return true;
                return /^Web\s+\S+/.test(t) && /[░▓▒█]/.test(t);
            };

            const splitConcatenatedOutput = (text) => {
                let s = String(text || '');
                s = s.replace(/reserved\.([A-Za-z]:\\)/g, 'reserved.\n$1');
                s = s.replace(/([^\n\r])>(?=[A-Za-z/\\])/g, '$1\n>');
                s = s.replace(/([^\n\r])(Starting project at )/g, '$1\n$2');
                s = s.replace(/([^\n\r])(Starting Metro Bundler)/g, '$1\n$2');
                s = s.replace(/(\.mjs)([A-Z])/g, '$1\n$2');
                s = s.replace(/(\.)\[electronmon\]/g, '$1\n[electronmon]');
                return s;
            };

            const normalizeTerminalNoiseLine = (line) => {
                let text = String(line ?? '').replace(/\u0000/g, '').trimEnd();
                if (!text) return '';

                // Mode raw: tampilkan output asli (hanya strip karakter null)
                if (terminalOutputMode === 'raw') return text;

                // Artefak auto-confirm PTY lama: "YD:\path>"
                text = text.replace(/^Y(?=[A-Za-z]:[\\/])/, '');

                // Jika prompt menempel di depan output, buang bagian prompt-nya.
                text = text.replace(/^[A-Za-z]:[\\/][^>]*>\s*(?=[A-Za-z]:[\\/].+)/, '');

                // Noise bawaan cmd/windows yang tidak relevan untuk user.
                if (/^Microsoft Windows \[Version/i.test(text)) return '';
                if (/^\(c\) Microsoft Corporation\./i.test(text)) return '';
                if (/^>\s*chcp\s+65001\s*$/i.test(text)) return '';
                if (/^>\s*nul\s*$/i.test(text)) return '';

                // Prompt murni (tanpa output) cukup diabaikan agar tidak berantakan.
                if (/^[A-Za-z]:[\\/].*>\s*$/.test(text)) return '';
                // PowerShell prompt: "PS D:\path>" atau "PS C:\path> "
                if (/^PS\s+[A-Za-z]:[\\/].*>\s*$/.test(text)) return '';

                // Duplicate info dari shell wrapper, sudah cukup diwakili status akhir terminal.
                if (/electron\.exe exited with signal sigint/i.test(text)) return '';

                // Sembunyikan command internal hasil injeksi flag cache agar output tetap bersih.
                if (/^>\s*electron\b/i.test(text) && /--user-data-dir|--disable-gpu-shader-disk-cache/i.test(text)) {
                    return '';
                }

                return text;
            };

            const fixTerminalEncoding = (text) => {
                let s = String(text || '');
                if (!s) return s;
                const replacements = [
                    ['≡ƒöÇ', '🔀'],
                    ['ΓåÆ', '→'],
                    ['Γ£à', '✅'],
                    ['â†’', '→'],
                    ['âœ…', '✅'],
                ];
                for (const [bad, good] of replacements) {
                    if (s.includes(bad)) s = s.split(bad).join(good);
                }
                if (/ΓåÆ|Γ£à|≡ƒ|â†|âœ|Ã.|Â./.test(s)) {
                    try {
                        const bytes = new Uint8Array(s.length);
                        for (let i = 0; i < s.length; i += 1) bytes[i] = s.charCodeAt(i) & 0xff;
                        const recovered = new TextDecoder('utf-8').decode(bytes);
                        if (recovered && !/[\uFFFD]{2,}/.test(recovered)) s = recovered;
                    } catch { /* ignore */ }
                }
                return s;
            };

            const stripTerminalControls = (chunk) => {
                let s = fixTerminalEncoding(String(chunk || ''));
                s = s.replace(/\x1B\][^\x07\x1B]*(?:\x07|\x1B\\)/g, '');
                s = s.replace(/\x1B\[[0-?]*[ -/]*[@-~]/g, '');
                s = s.replace(/[\x00-\x08\x0B-\x1F\x7F]/g, (ch) => (
                    ch === '\n' || ch === '\r' || ch === '\t' ? ch : ''
                ));
                return s;
            };

            const renderStreamText = (text) => {
                const decoded = decodeTerminalDisplayUrls(text);
                try {
                    return cmd._renderAnsiToHtml ? cmd._renderAnsiToHtml(decoded) : decoded;
                } catch {
                    return decoded;
                }
            };

            const finalizeLiveStreamRow = () => {
                if (!streamOut.liveRow) return;
                try { streamOut.liveRow.disable(); } catch { /* ignore */ }
                try { streamOut.liveRow.hideTime?.(); } catch { /* ignore */ }
                streamOut.liveRow = null;
            };

            const writeStreamLine = (line, kind = 'stdout') => {
                finalizeLiveStreamRow();
                const text = normalizeTerminalNoiseLine(line);
                if (!text) return;
                if (_termOutputAcc.length < 8000) _termOutputAcc += text + '\n';
                const norm = text.replace(/\s+/g, ' ').trim();
                const lastNorm = String(streamOut.lastLine || '').replace(/\s+/g, ' ').trim();
                if (norm && norm === lastNorm) return;

                if (isBundlerProgressLine(text)) {
                    if (!streamOut.progressRow) {
                        streamOut.progressRow = new CommandRow(cmd, () => {});
                        try { streamOut.progressRow.disable(); } catch { /* ignore */ }
                        try { streamOut.progressRow.hideUser(); } catch { /* ignore */ }
                        try { streamOut.progressRow.hideTime(); } catch { /* ignore */ }
                    }
                    streamOut.progressRow.setEntry(renderStreamText(text));
                    streamOut.lastLine = text;
                    try { cmd.commandRow?.disable?.(); } catch { /* ignore */ }
                    return;
                }

                streamOut.progressRow = null;
                streamOut.lastLine = text;
                const row = new CommandRow(cmd, () => {});
                try { row.disable(); } catch { /* ignore */ }
                try { row.hideUser(); } catch { /* ignore */ }
                try { row.hideTime(); } catch { /* ignore */ }
                row.setEntry(renderStreamText(text));
                if (kind === 'stderr') {
                    try { row.commandEntry?.classList?.add('error'); } catch { /* ignore */ }
                }
                try { cmd.commandRow?.disable?.(); } catch { /* ignore */ }
            };

            const updateLiveStreamLine = (line, kind = 'stdout') => {
                const text = normalizeTerminalNoiseLine(line);
                if (!text) {
                    finalizeLiveStreamRow();
                    return;
                }
                if (isBundlerProgressLine(text)) {
                    writeStreamLine(text, kind);
                    return;
                }
                if (!streamOut.liveRow) {
                    streamOut.liveRow = new CommandRow(cmd, () => {});
                    try { streamOut.liveRow.disable(); } catch { /* ignore */ }
                    try { streamOut.liveRow.hideUser(); } catch { /* ignore */ }
                    try { streamOut.liveRow.hideTime(); } catch { /* ignore */ }
                    try { cmd.commandRow?.disable?.(); } catch { /* ignore */ }
                }
                streamOut.liveRow.setEntry(renderStreamText(text));
                if (kind === 'stderr') {
                    try { streamOut.liveRow.commandEntry?.classList?.add('error'); } catch { /* ignore */ }
                }
            };

            const openNodeServerInElectron = async (url) => {
                if (!url || !window.electronAPI?.openNodeServerWindow) return;
                if (interactiveSession.nodeServerOpened) return;
                interactiveSession.nodeServerOpened = true;
                cmd.success(`🌐 Server siap, membuka di jendela...`);
                try {
                    const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
                    const warmUrl = url.replace(/\/+$/, '') + '/';
                    const isReady = async () => {
                        if (!window.electronAPI?.warmExpoWeb) return true;
                        try {
                            const res = await window.electronAPI.warmExpoWeb({ url: warmUrl });
                            return Boolean(res?.ok);
                        } catch { return false; }
                    };
                    let ready = await isReady();
                    for (let i = 0; !ready && i < 120; i += 1) {
                        await wait(500);
                        ready = await isReady();
                    }
                    if (!ready) {
                        cmd.warning(`Server ${url} belum siap setelah menunggu, tetap mencoba membuka...`);
                    }
                    const result = await window.electronAPI.openNodeServerWindow({
                        url: url.replace(/\/+$/, ''),
                        width: 1180,
                        height: 760,
                        title: `Node.js Server - ${url}`,
                        reload: true,
                    });
                    if (result?.ok) {
                        cmd.success(`✅ ${url} dibuka di jendela baru.`);
                    } else {
                        cmd.error(`Gagal membuka jendela: ${String(result?.error || 'unknown')}`);
                    }
                } catch (e) {
                    cmd.error(`Gagal membuka web window: ${String(e?.message || e)}`);
                }
            };

            const ingestTerminalChunk = (state, chunk, kind = 'stdout') => {
                const s = splitConcatenatedOutput(stripTerminalControls(chunk));
                const expoUrl = parseExpoWebUrl(s);
                if (expoUrl) interactiveSession.webUrl = expoUrl;

                // Deteksi URL localhost dari stdout (Node.js server)
                if (kind === 'stdout' && interactiveSession.nodeServerPort > 0 && !interactiveSession.nodeServerOpened) {
                    const urlMatch = s.match(/https?:\/\/localhost:(\d+)/i);
                    if (urlMatch) {
                        interactiveSession.nodeServerUrl = urlMatch[0].replace(/\/+$/, '');
                    }
                }

                for (let i = 0; i < s.length; i += 1) {
                    const ch = s[i];
                    if (ch === '\r') {
                        if (s[i + 1] === '\n') {
                            writeStreamLine(state.buffer, kind);
                            checkAndOpenNodeServer(state.buffer);
                            state.buffer = '';
                            i += 1;
                        } else {
                            // Progress bar TTY: \r menimpa baris yang sama, bukan baris baru.
                            state.buffer = '';
                        }
                    } else if (ch === '\n') {
                        writeStreamLine(state.buffer, kind);
                        checkAndOpenNodeServer(state.buffer);
                        state.buffer = '';
                    } else {
                        state.buffer += ch;
                    }
                }

                if (state.buffer) {
                    updateLiveStreamLine(state.buffer, kind);
                }
            };

            const checkAndOpenNodeServer = (line) => {
                if (interactiveSession.nodeServerOpened) return;
                if (interactiveSession.nodeServerPort <= 0) return;
                const portPattern = new RegExp(`https?://localhost:${interactiveSession.nodeServerPort}`, 'i');
                const m = (line || '').match(portPattern);
                if (m) {
                    const url = m[0].replace(/\/+$/, '');
                    interactiveSession.nodeServerUrl = url;
                    setTimeout(() => openNodeServerInElectron(url), 800);
                }
            };

            const flushTerminalStream = (state, kind = 'stdout', force = false) => {
                if (force && state.buffer) {
                    writeStreamLine(state.buffer, kind);
                    state.buffer = '';
                }
                finalizeLiveStreamRow();
                if (force) {
                    streamOut.progressRow = null;
                    streamOut.lastLine = '';
                }
            };

            let _termOutputAcc = '';
            const execResult = await new Promise((resolve) => {
                const offData = window.electronAPI.onTerminalShellData((payload) => {
                    if (!payload || payload.requestId !== requestId) return;
                    if (payload.stream === 'stderr') {
                        ingestTerminalChunk(stderrState, payload.data || '', 'stderr');
                    } else {
                        ingestTerminalChunk(stdoutState, payload.data || '', 'stdout');
                    }
                });
                const offExit = window.electronAPI.onTerminalShellExit((payload) => {
                    if (!payload || payload.requestId !== requestId) return;
                    if (interactiveSession.requestId === requestId) {
                        interactiveSession.requestId = '';
                        interactiveSession.isExpo = false;
                        interactiveSession.webUrl = '';
                        interactiveSession.openingWeb = false;
                        interactiveSession.nodeServerPort = 0;
                        interactiveSession.nodeServerUrl = '';
                        interactiveSession.nodeServerOpened = false;
                    }
                    flushTerminalStream(stdoutState, 'stdout', true);
                    flushTerminalStream(stderrState, 'stderr', true);
                    offData?.();
                    offExit?.();
                    try {
                        localStorage.setItem('nx-terminal-last-output', JSON.stringify({
                            command: execCommand,
                            cwd: toDisplayPath(shellCwd),
                            output: _termOutputAcc.slice(0, 8000),
                            exitCode: Number(payload.exitCode || 0),
                            ts: Date.now(),
                        }));
                    } catch { /* ignore */ }
                    if (payload.error) {
                        cmd.error(String(payload.error));
                        activeShellRequestId = '';
                        dispatchTerminalState('error', {
                            command: execCommand,
                            exitCode: Number(payload.exitCode || 1),
                            error: String(payload.error),
                        });
                        resolve({ exitCode: Number(payload.exitCode || 1), error: String(payload.error) });
                        return;
                    }
                    activeShellRequestId = '';
                    dispatchTerminalState(Number(payload.exitCode || 0) === 0 ? 'success' : 'error', {
                        command: execCommand,
                        exitCode: Number(payload.exitCode || 0),
                    });
                    resolve({ exitCode: Number(payload.exitCode || 0), error: '' });
                });
                void window.electronAPI.terminalShellStream({
                    requestId,
                    command: execCommand,
                    cwd: cwdWin,
                    shell: getActiveShell(),
                }).catch((err) => {
                    offData?.();
                    offExit?.();
                    if (interactiveSession.requestId === requestId) {
                        interactiveSession.requestId = '';
                        interactiveSession.isExpo = false;
                        interactiveSession.webUrl = '';
                        interactiveSession.openingWeb = false;
                        interactiveSession.nodeServerPort = 0;
                        interactiveSession.nodeServerUrl = '';
                        interactiveSession.nodeServerOpened = false;
                    }
                    cmd.error(String(err?.message || err));
                    activeShellRequestId = '';
                    dispatchTerminalState('error', {
                        command: execCommand,
                        exitCode: 1,
                        error: String(err?.message || err),
                    });
                    resolve({ exitCode: 1, error: String(err?.message || err) });
                });
            });
            const exitCode = Number(execResult?.exitCode || 0);
            if (exitCode !== 0) {
                if (!execResult?.error) {
                    cmd.error(`Command exited with code ${exitCode}`);
                }
            }
        };

        const stopActiveNativeShell = async () => {
            const reqId = String(activeShellRequestId || interactiveSession.requestId || '').trim();
            if (!reqId) {
                cmd.info('Tidak ada proses shell aktif.');
                dispatchTerminalState('idle', { stopped: false, message: 'no-active-process' });
                return;
            }

            if (!window.electronAPI?.terminalShellStop) {
                cmd.error('API terminalShellStop belum tersedia. Restart aplikasi Electron.');
                dispatchTerminalState('error', {
                    requestId: reqId,
                    stopped: false,
                    error: 'terminalShellStop-unavailable',
                });
                return;
            }

            try {
                const stopped = await window.electronAPI.terminalShellStop({ requestId: reqId, signal: 'SIGINT' });
                if (!stopped?.ok) {
                    cmd.error(String(stopped?.error || 'Gagal menghentikan proses shell aktif.'));
                    dispatchTerminalState('error', {
                        requestId: reqId,
                        stopped: false,
                        error: String(stopped?.error || 'stop-failed'),
                    });
                    return;
                }
                cmd.warning('Proses shell dihentikan oleh pengguna.');
                dispatchTerminalState('error', {
                    requestId: reqId,
                    stopped: true,
                    reason: 'user-stop',
                });
            } catch (e) {
                cmd.error(String(e?.message || e));
                dispatchTerminalState('error', {
                    requestId: reqId,
                    stopped: false,
                    error: String(e?.message || e),
                });
            }
        };

        cmd.addCommand('shell-stop', async function () {
            await stopActiveNativeShell();
        }, 'Stop active native shell process in current terminal tab');
        cmd.addCommand('stop-shell', async function () {
            await stopActiveNativeShell();
        }, 'Alias shell-stop');

        cmd.addCommand('output-mode mode?', function (command) {
            const modeArg = String(command.getArgument('mode') || '').trim().toLowerCase();
            if (!modeArg) {
                cmd.info(`Output mode: ${terminalOutputMode}`);
                cmd.info('Gunakan: output-mode clean | output-mode raw');
                return;
            }
            if (modeArg !== 'clean' && modeArg !== 'raw') {
                cmd.error('Mode tidak valid. Pakai: clean atau raw.');
                return;
            }
            terminalOutputMode = writeTerminalOutputMode(modeArg);
            cmd.success(`Output mode diubah ke: ${terminalOutputMode}`);
        }, 'Set/get terminal output mode (clean/raw)');

        cmd.addCommand('output-clean', function () {
            terminalOutputMode = writeTerminalOutputMode('clean');
            cmd.success('Output mode: clean');
        }, 'Set output mode ke clean');

        cmd.addCommand('output-raw', function () {
            terminalOutputMode = writeTerminalOutputMode('raw');
            cmd.success('Output mode: raw');
        }, 'Set output mode ke raw');

        cmd.addCommand('clean', function () {
            terminalOutputMode = writeTerminalOutputMode('clean');
            cmd.success('Output mode: clean');
        }, 'Alias output-clean');

        cmd.addCommand('rawmode', function () {
            terminalOutputMode = writeTerminalOutputMode('raw');
            cmd.success('Output mode: raw');
        }, 'Alias output-raw');

        const registerNativeShellAlias = (name) => {
            cmd.addCommand(`${name} args*`, async function (command) {
                const args = String(command.getArgument('args') || '').trim();
                const full = `${name}${args ? ` ${args}` : ''}`;
                await runNativeShellCommand(full);
            }, `Run native ${name} command`);
        };

        ['npm', 'npx', 'node', 'git', 'yarn', 'pnpm', 'rmdir', 'del', 'rd', 'mkdir', 'copy', 'move', 'xcopy', 'ren', 'type', 'fc', 'attrib', 'tree', 'robocopy',
         // Unix/cross-platform
         'cat', 'touch', 'grep', 'find', 'mv', 'cp', 'rm', 'chmod', 'chown', 'curl', 'wget', 'ssh', 'scp',
         // Windows extras
         'ipconfig', 'ping', 'netstat', 'tasklist', 'sc', 'reg', 'sfc', 'chkdsk', 'diskpart', 'wmic',
         'set', 'setx', 'where', 'which', 'echo', 'ver', 'systeminfo', 'hostname',
         // PowerShell binary (untuk mode non-PS shell bisa invoke pwsh langsung)
         'powershell', 'pwsh',
         // Tools dev umum
         'code', 'python', 'python3', 'pip', 'pip3', 'cargo', 'go', 'java', 'javac', 'mvn', 'gradle',
         'dotnet', 'php', 'composer', 'ruby', 'gem', 'rails', 'make', 'cmake', 'gcc', 'g++', 'clang',
         'docker', 'docker-compose', 'kubectl', 'helm', 'terraform', 'ansible',
         'ffmpeg', 'convert', 'magick', 'openssl', 'gpg', 'tar', 'zip', 'unzip', '7z',
        ].forEach(registerNativeShellAlias);

        // ── Claude CLI ────────────────────────────────────────────────────────
        const _claudeSessions = new WeakMap();
        const _runClaudePrompt = async (prompt) => {
            const escaped = prompt.replace(/"/g, '\\"');
            // Pipe empty string ke stdin agar claude tidak menunggu stdin (cegah warning 3s)
            await runNativeShellCommand(`echo. | claude --print "${escaped}"`);
        };
        const _claudeLoop = (session) => {
            cmd.prompt('claude>', (userPrompt) => {
                if (!userPrompt || !userPrompt.trim()) { _claudeLoop(session); return; }
                const trimmed = userPrompt.trim();
                if (trimmed.toLowerCase() === 'exit' || trimmed.toLowerCase() === 'quit') {
                    _claudeSessions.delete(cmd.container);
                    cmd.info('Claude session closed.');
                    cmd.startNewCommand();
                    return;
                }
                _runClaudePrompt(trimmed).then(() => {
                    cmd.info('');
                    _claudeLoop(session);
                });
            });
        };
        cmd.addCommand('claude args*', async function (command) {
            const args = String(command.getArgument('args') || '').trim();
            if (args) {
                // claude <prompt> — jalankan langsung non-interaktif
                await _runClaudePrompt(args);
            } else {
                // claude (tanpa args) — buka sesi interaktif
                if (!_claudeSessions.has(cmd.container)) {
                    _claudeSessions.set(cmd.container, { active: true });
                    cmd.info('=== Claude CLI ===');
                    cmd.info('Ketik prompt, Enter untuk kirim. Ketik "exit" untuk keluar.');
                    cmd.info('');
                }
                _claudeLoop(_claudeSessions.get(cmd.container));
            }
            return false;
        }, 'Claude CLI — claude <prompt> atau mode interaktif');

        dispatchTerminalState('idle', { ready: true });

        // Listener inject-command dari AI Chat (poin 53)
        const _injectCommandHandler = (event) => {
            const detail = event?.detail || {};
            const hostId = String(detail.hostId || '').trim();
            const command = String(detail.command || '').trim();
            if (!command) return;
            const host = selector && typeof selector.closest === 'function'
                ? selector.closest('.beranda-terminal-host')
                : null;
            const thisHostId = String(host?.dataset?.terminalHostId || '').trim();
            if (hostId && thisHostId && hostId !== thisHostId) return;
            // Guard: blokir kill-all commands berbahaya
            if (/\btaskkill\b.*\/f\b.*\/im\b.*node/i.test(command) ||
                /\bkillall\b\s+node/i.test(command) ||
                /\bpkill\b\s+-f\s+node/i.test(command)) return;
            try { cmd.run(command); } catch { /* ignore */ }
        };
        window.addEventListener('nexa-terminal-inject-command', _injectCommandHandler);

        const _shellChangedHandler = (event) => {
            const detail = event?.detail || {};
            const hostId = String(detail.hostId || '').trim();
            const host = selector && typeof selector.closest === 'function'
                ? selector.closest('.beranda-terminal-host')
                : null;
            const thisHostId = String(host?.dataset?.terminalHostId || '').trim();
            if (hostId && thisHostId && hostId !== thisHostId) return;
            const label = String(detail.label || detail.shell || '');
            if (!label) return;
            cmd.info(`▶ Shell aktif: ${label}`);
            try { cmd.commandRow?.hideTime?.(); } catch { /* ignore */ }
        };
        window.addEventListener('nexa-terminal-shell-changed', _shellChangedHandler);

        // Daftarkan cleanup agar terminal-panel.js bisa dispose saat unmount
        try {
            const host = selector && typeof selector.closest === 'function'
                ? selector.closest('.beranda-terminal-host')
                : null;
            if (host) {
                if (!Array.isArray(host.__nexaTerminalCleanups)) host.__nexaTerminalCleanups = [];
                host.__nexaTerminalCleanups.push(() => {
                    window.removeEventListener('nexa-terminal-inject-command', _injectCommandHandler);
                    window.removeEventListener('nexa-terminal-shell-changed', _shellChangedHandler);
                });
            }
        } catch { /* ignore */ }

        registerServerCommands(cmd, {
          shellCwd: { get: () => shellCwd, set: (v) => { shellCwd = v; } },
          shellNormalize,
          normalizeSlash,
          toDisplayPath,
          shellResolvePath,
          syncPromptWorkingDirectory,
          interactiveSession,
          runNativeShellCommand,
          nexaRunWithTermWait,
        });

        cmd.addCommand("api", function () {
            return APIConsole(cmd);
        }, 'Kirim HTTP request interaktif (GET/POST/PUT/PATCH/DELETE + Auth)');


        cmd.addCommand("debug", async function () {
            return await debug(cmd)
        }, 'Scan proyek aktif dan tampilkan syntax errors');

        cmd.addCommand("agent", async function () {
            return await agent(cmd)
        }, 'Agent Cli');

     
        cmd.addCommand("problems", async function () {
            return await problems(cmd)
        }, 'Tampilkan semua errors dari hasil debug terakhir');


        cmd.addCommand("date", function () {
            cmd.output(new Date().toString());
            try { cmd.commandRow?.hideTime?.(); } catch { /* ignore */ }
        }, 'Show current date and time');

        cmd.addCommand("whoami", function () {
            cmd.output(String(cmd.username || 'NEXA'));
            try { cmd.commandRow?.hideTime?.(); } catch { /* ignore */ }
        }, 'Show current username');

        registerShortcutsCommand(cmd);


        cmd.addCommand("devrun args*", async function (command) {
            const args = String(command.getArgument('args') || '').trim();

            // Pindah ke directory editor aktif
            try {
                const raw = localStorage.getItem('nx-discovery-editor-active');
                if (raw) {
                    const row = JSON.parse(raw);
                    const filePath = String(row?.filePath || '').trim();
                    if (filePath) {
                        const norm = filePath.replace(/\\/g, '/');
                        const segs = norm.split('/').filter(Boolean);
                        if (/\.[A-Za-z0-9_-]+$/.test(segs[segs.length - 1] || '')) segs.pop();
                        if (segs.length > 0) {
                            const dir = /^[A-Za-z]:$/.test(segs[0])
                                ? (segs.length > 1 ? `${segs[0]}/${segs.slice(1).join('/')}` : `${segs[0]}/`)
                                : `/${segs.join('/')}`;
                            shellCwd = shellNormalize(dir);
                            syncPromptWorkingDirectory();
                        }
                    }
                }
            } catch { /* ignore */ }

            // Pakai logika run yang sudah ada — baca package.json, cek port, jalankan
            if (args === 'stop') {
                await stopActiveNativeShell();
            } else {
                cmd.run('run');
            }
        }, 'Run project dari editor aktif via package.json');

        cmd.addCommand("phpserver args*", async function (command) {
            const args = String(command.getArgument('args') || '').trim();
            const parts = args ? args.split(/\s+/) : [];
            const sub = (parts[0] || 'start').toLowerCase();
            const api = globalThis.electronAPI || globalThis.window?.electronAPI;
            if (!api?.phpServerStart) {
                cmd.output('[phpServer] API tidak tersedia — pastikan versi Electron sudah diperbarui.');
                return;
            }
            if (sub === 'stop') {
                const port = parts[1] ? Number(parts[1]) : undefined;
                const res = await api.phpServerStop(port ? { port } : {}).catch(e => ({ ok: false, error: e?.message }));
                cmd.output(res?.ok ? `[phpServer] ${res.stopped} server dihentikan.` : `[phpServer] Gagal: ${res?.error}`);
                return;
            }
            if (sub === 'status') {
                const res = await api.phpServerStatus({}).catch(e => ({ ok: false, error: e?.message }));
                if (res?.ok && res.servers?.length) {
                    res.servers.forEach(s => cmd.output(`  Port ${s.port}  PID ${s.pid}  ${s.url}  ${s.cwd}`));
                } else if (res?.ok) {
                    cmd.output('[phpServer] Tidak ada server yang aktif.');
                } else {
                    cmd.output(`[phpServer] Gagal: ${res?.error}`);
                }
                return;
            }
            // start (default) — spawn server lalu buka di browser panel internal
            const portArg = parts[1] ? Number(parts[1]) : undefined;
            const cwd = toDisplayPath(shellCwd);
            if (!cwd) {
                cmd.output('[phpServer] Tidak bisa menentukan folder — gunakan cd <path> terlebih dahulu.');
                return;
            }
            cmd.output(`[phpServer] Memulai PHP server di "${cwd}"${portArg ? ` port ${portArg}` : ''} …`);
            const res = await api.phpServerStart({ cwd, port: portArg }).catch(e => ({ ok: false, error: e?.message }));
            if (res?.ok) {
                const routerLabel = res.routerIsExternal
                    ? '  router: nexa-builtin'
                    : (res.router ? `  router: ${res.router}` : '');
                cmd.output(`[phpServer] Server aktif: ${res.url}  (PID ${res.pid || '?'})${routerLabel}`);
                // Buka di browser panel internal (pola sama dengan nx-browser-open dari chat/markdown)
                window.dispatchEvent(new CustomEvent('nx-browser-open', { detail: { url: res.url } }));
            } else {
                cmd.output(`[phpServer] Gagal: ${res?.error || 'unknown error'}`);
            }
        }, 'phpserver [start|stop|status] [port] — kelola PHP built-in server');


        cmd.addCommand("nx args*", async function (command) {
        const args = String(command.getArgument('args') || '').trim();
        const firstArg = args.split(/\s+/)[0] || '';
        if (firstArg) {
            // Route ke handler berikutnya berdasarkan firstArg
            // Misal: nx dev → firstArg = 'dev'
            if (firstArg === 'dev') {
               return await developer(cmd)
            } else if (firstArg === 'bundle') {
               return await bundle(cmd)
            } else if (firstArg === 'test') {
               return await nxTest(cmd)
            } else {
            cmd.success(`${firstArg}`);
            }
        } else {
            cmd.success('nx (no arguments)');
        }
    }, "Developer Extensions (nx <subcommand>)");
 

// DEVELOPMEN TEXTING MODE

           cmd.addCommand("mode args*", async function (command) {
            const fullArgs = String(command.getArgument('args') || '').trim();
            const parts = fullArgs.split(/\s+/);
            const firstArg = parts[0] || '';
            const restArgs = parts.slice(1).join(' ').trim();
            if (firstArg) {
                await mode(cmd, firstArg, restArgs);
            } else {
                cmd.success('mode (no arguments)');
            }
            return false;
        }, "DEVELOPMEN TEXTING MODE");
 
      


   // DEVELOPMEN TEXTING MODE
        return cmd;
    };

})();
